"use client"
import { useState } from "react"

export default function Login() {
  // ESTADO: Guarda os dados do formulário (email e senha)
  // useState cria uma variável reativa que atualiza a página quando muda
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  })
  
  // FUNÇÃO: Chamada sempre que usuário digita algo nos inputs
  // React.ChangeEvent<HTMLInputElement> é o tipo do evento de input
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    // Atualiza o estado mantendo os valores antigos e alterando só o campo atual
    // [e.target.name] pega o atributo "name" do input (email ou password)
    // e.target.value pega o valor que usuário digitou
    setFormData({
      ...formData,  // Espalha os valores antigos
      [e.target.name]: e.target.value  // Sobrescreve só o campo atual
    })
  }

  // FUNÇÃO: Chamada quando usuário clica no botão "Entrar"
  // async porque vai fazer requisição para API (espera resposta)
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()  // Impede a página de recarregar (comportamento padrão do form)
    
    try {
      // fetch: Função JavaScript para fazer requisições HTTP
      // POST: Método HTTP para enviar dados
      // /api/auth/login: Nossa API que criamos
      const response = await fetch('/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'  // Diz que estamos enviando JSON
        },
        body: JSON.stringify(formData)  // Converte objeto JavaScript para string JSON
      })
      
      // Converte resposta da API para objeto JavaScript
      const data = await response.json()
      
      // Verifica se login deu certo
      if (data.success) {
        // SUCESSO: Usuário encontrado e senha correta
        console.log('Login realizado!', data.user)
        alert('Login realizado com sucesso!')
        // Aqui poderia redirecionar para dashboard: window.location.href = '/dashboard'
        window.location.href = '/dashboard'
      } else {
        // ERRO: Usuário não encontrado ou senha incorreta
        console.error('Erro no login:', data.error)
        alert(data.error)
      }
    } catch (error) {
      // ERRO DE REDE: API não respondeu ou outro problema
      console.error('Erro na requisição:', error)
      alert('Erro ao conectar com o servidor')
    }
  }




  
  // RENDER: Tudo que aparece na tela
  return (
    // Container principal: tela inteira centralizada
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      {/* Card do formulário: caixa branca com sombra */}
      <div className="bg-white p-8 rounded-lg shadow-md w-full max-w-md">
        {/* Header: título e subtítulo */}
        <div className="text-center mb-6">
          <h1 className="text-3xl font-bold text-gray-900">Bem-vindo</h1>
          <p className="text-gray-600 mt-2">Faça login na sua conta</p>
        </div>

        {/* FORMULÁRIO: onde usuário digita dados */}
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Campo Email */}
          <div>
            <label className="block text-sm font-medium text-gray-700">Email</label>
            <input 
              type="email" 
              name="email"                    // ← IMPORTANTE: name="email" para o handleChange saber qual campo atualizar
              value={formData.email}           // ← IMPORTANTE: Mostra o valor atual do estado
              onChange={handleChange}           // ← IMPORTANTE: Chama handleChange quando usuário digita
              className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md"
              placeholder="seu@email.com"
              required  // ← Obrigatório preencher
            />
          </div>
          
          {/* Campo Senha */}
          <div>
            <label className="block text-sm font-medium text-gray-700">Senha</label>
            <input 
              type="password" 
              name="password"                 // ← name="password" para o handleChange
              value={formData.password}          // ← Mostra senha atual do estado
              onChange={handleChange}           // ← Atualiza estado quando digita
              className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md"
              placeholder="•••••••"
              required  // ← Obrigatório preencher
            />
          </div>

          {/* Botão de Submit */}
          <button 
            type="submit"                   // ← type="submit" dispara o onSubmit do form
            className="w-full bg-blue-900 text-white py-2 px-4 rounded-md hover:bg-blue-700"
          >
            Entrar
          </button>
        </form>

        {/* Footer: link para cadastro */}
        <div className="mt-6 text-center">
          <p className="text-sm text-gray-600">
            Não tem conta? <a href="/register" className="text-blue-600">Cadastre-se</a>
          </p>
        </div>
      </div>
    </div>
  );
}
